int calcPrimitiveRoot(int N) {
  vector<int> fac;

  // phi(N) 返回 N 的欧拉函数值，实现略
  int PHI_N = phi(N);
  calcFactor(PHI_N, fac);

  for (int i = 0; i < fac.size(); ++i) fac[i] = PHI_N / fac[i];
  for (int g = 2; ; ++g) {
    bool flag = true;
    for (int i = 0; i < fac.size(); ++i) {
      // powerMod 返回 $g^{fac[i]} \mod N$，实现略
      if (powerMod(g, fac[i], N) == 1) {
        flag = false;
        break;
      }
    }
    if (flag) return g;
  }    
}

