typedef long long LL;
bool isprime[MAXN];
int prime[MAXN], tot;

void sievePrimes() {
  memset(isprime, 1, sizeof isprime);
  tot = 0;
  for (int x = 2; x < MAXN; ++x) {
      if (isprime[x]) prime[tot++] = x;
      for (int i = 0; i < tot; ++i) {
          // 防止乘法溢出
          if ((LL) prime[i]*x >= MAXN) break;

          isprime[prime[i]*x] = false;

          // 保证每个数仅被其最小正素因子标记
          if (x % prime[i] == 0) break;
      }
  }
}

