typedef long long LL;
int phi[N];

void sievePhi() {
  memset(phi, 0, sizeof phi);
  phi[1] = 1;
  for (int i = 2; i < N; ++i) {
    if (!phi[i]) {
      for (int j = i; j < N; j += i) {
        if (!phi[j]) phi[j] = j;    
        phi[j] = phi[i] / i * (i - 1); // 先除后乘防止溢出
      }
    }
  }
}

typedef long long LL;
int phi[N], prime[N], tot;

void sievePhi() {
  memset(phi, 0, sizeof phi);
  phi[1] = 1;
  tot = 0;

  for (int i = 2; i < N; ++i) {
    if (!phi[i]) {
      phi[i] = i - 1;
      prime[tot++] = i;
    }
    for (int j = 0; j < tot; ++j) {
      LL ret = (LL) prime[j] * i;
      if (ret >= N) break;
      if (i % prime[j] == 0) {
        phi[ret] = phi[i] * prime[j]; // 对应 e 整除 X' 的情况
        break;
      }
      phi[ret] = phi[i] * (prime[j] - 1); // 对应 e 不整除 X' 的情况
    }
  }
}

typedef long long LL;
void extendEuclid(LL a, LL& x, LL b, LL &y, LL& d) { // d=gcd(a,b)
  if (!b) { 
    d = a;
    x = 1;
    y = 0; 
  } 
  else { 
    extendEuclid(b, y, a%b, x, d);
    y -= (a / b) * x; 
  }
}

