typedef long long LL;
LL powerMod(LL A, LL x, LL mod) { // 返回 A^x%mod
  LL ans = 1;
  for(; x > 0; x >>= 1, A = A * A % mod) {
    if (x & 1) ans = ans * A % mod;
  }
  return ans;
}

LL inv(LL A, LL mod) {
  return powerMod(A, mod-2, mod);   
}

