LL crt(int N, int* a, int* m) {
  LL M = 1, ans = 0;
  for (int i = 0; i < N; ++i) M *= m[i];
  for (int i = 0; i < N; ++i) {
    LL w = M / m[i], x, y, d;
    extendEuclid(w, x, m[i], y, d);
    ans = (ans + x * w * a[i]) % M;
  }
  return ans;
}

